-- Load required LuaXML library
local xml = require "lxp.lxp"

-- Function to handle incoming requests
function handle_request(client)
    local request_body = ""
    
    -- Read the entire request body
    while true do
        local chunk = client:request(4096)  -- read up to 4096 bytes at a time
        if not chunk then break end  -- break loop when no more data is received
        request_body = request_body .. chunk
    end

    -- Parse the XML request body
    local parser = xml.parser()
    local status, root_element = parser:request(request_body)
    
    if status ~= "ok" or not root_element then
        client:send("HTTP/1.1 400 Bad Request\r\n\r\nInvalid XML")
        return
    end

    -- Extract data from the parsed XML
    local requestData = {}
    for node in parser:iterate(root_element, "*") do
        if node.tag then
            requestData[node.tag] = node.data or ""
        end
    end
    
    -- Process the extracted data (example processing)
    local response_data = "Processed data: " .. requestData["name"] .. ", " .. requestData["age"]
    
    -- Send response to client
    client:send("HTTP/1.1 200 OK\r\nContent-Type: text/plain\r\n\r\n" .. response_data)
end

